import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, StatusBadge, Pagination, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import type { FixedAssetDto } from '../../../services/tscd/models';
import { formatDateLocal, formatVnd } from '../../../utils/formatters';
import erp from '../../../styles/erpPage.module.css';

const PAGE_SIZE = 20;

const TscdListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const [page, setPage] = useState(1);
  const [items, setItems] = useState<FixedAssetDto[]>([]);
  const [loading, setLoading] = useState(false);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      tscdService.getAssets({ page, pageSize: PAGE_SIZE })
        .then(data => { if (!cancelled) setItems(data); })
        .catch(err => { if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải TSCĐ', type: 'error' })); })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [page]);

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-building" /> Tài sản cố định</h1></div>
        <div className={erp.headerActions}>
          <Button variant="primary" onClick={() => navigate('/tscd/them')}><i className="fas fa-plus" /> Thêm mới</Button>
        </div>
      </div>
      <div className={erp.tableCard}>
        {loading ? <div className={erp.loading}>Đang tải...</div> : items.length === 0 ? <div className={erp.empty}>Không có dữ liệu</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead><tr><th>Mã TS</th><th>Tên</th><th>Ngày mua</th><th className={erp.colRight}>Nguyên giá</th><th className={erp.colRight}>GT còn lại</th><th>TT</th></tr></thead>
              <tbody>{items.map(r => (
                <tr key={r.id}>
                  <td><button type="button" className={erp.codeLink} onClick={() => navigate(`/tscd/${r.id}`)}><code>{r.code}</code></button></td>
                  <td>{r.name}</td>
                  <td>{formatDateLocal(r.acquiredDate)}</td>
                  <td className={erp.colRight}>{formatVnd(r.originalCost)}</td>
                  <td className={erp.colRight}>{formatVnd(r.bookValue)}</td>
                  <td><StatusBadge status={r.status} /></td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default TscdListPage;
