import { apiClient, unwrap } from '@linm-soft/common-components';
import type { BffResponse } from '@linm-soft/common-components';
import type {
  FixedAssetDto,
  CreateFixedAssetDto,
  UpdateFixedAssetDto,
  FixedAssetFilter,
  DisposalDto,
  CreateDisposalDto,
  CreateAdjustmentDto,
  CreateTransferDto,
  SuspendDepreciationDto,
  DepreciationDto,
} from './models';

const BASE = '/assets';

export const tscdEndpoint = {
  getAssets: async (filter?: FixedAssetFilter) => {
    const qs = new URLSearchParams();
    if (filter?.search) qs.set('search', filter.search);
    if (filter?.status) qs.set('status', filter.status);
    if (filter?.categoryCode) qs.set('categoryCode', filter.categoryCode);
    if (filter?.departmentId) qs.set('departmentId', filter.departmentId);
    qs.set('page', String(filter?.page ?? 1));
    qs.set('pageSize', String(filter?.pageSize ?? 100));
    const res = await apiClient.get<BffResponse<FixedAssetDto[]>>(`${BASE}?${qs}`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },
  searchAssets: async (filter: FixedAssetFilter) => tscdEndpoint.getAssets(filter),
  getAsset: async (id: string) => {
    const res = await apiClient.get<BffResponse<FixedAssetDto>>(`${BASE}/${id}`);
    return unwrap(res);
  },
  createAsset: async (dto: CreateFixedAssetDto) => {
    const res = await apiClient.post<BffResponse<FixedAssetDto>>(`${BASE}`, dto);
    return unwrap(res);
  },
  updateAsset: async (id: string, dto: UpdateFixedAssetDto) => {
    const res = await apiClient.put<BffResponse<FixedAssetDto>>(`${BASE}/${id}`, dto);
    return unwrap(res);
  },
  getDisposals: async () => {
    const res = await apiClient.get<BffResponse<DisposalDto[]>>(`${BASE}/disposals`);
    const data = unwrap(res);
    return Array.isArray(data) ? data : [];
  },
  createDisposal: async (dto: CreateDisposalDto) => {
    const res = await apiClient.post<BffResponse<DisposalDto>>(`${BASE}/disposals`, dto);
    return unwrap(res);
  },
  createAdjustment: async (dto: CreateAdjustmentDto) => {
    const res = await apiClient.post<BffResponse<unknown>>(`${BASE}/adjustments`, dto);
    return unwrap(res);
  },
  createTransfer: async (dto: CreateTransferDto) => {
    const res = await apiClient.post<BffResponse<unknown>>(`${BASE}/transfers`, dto);
    return unwrap(res);
  },
  suspendDepreciation: async (dto: SuspendDepreciationDto) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/depreciation/suspend`, dto);
    return unwrap(res);
  },
  getDepreciation: async (month: number, year: number) => {
    const qs = new URLSearchParams({ month: String(month), year: String(year) });
    const res = await apiClient.get<BffResponse<DepreciationDto>>(`${BASE}/depreciation?${qs}`);
    return unwrap(res);
  },
  runDepreciation: async (month: number, year: number) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/depreciation/run`, { month, year });
    return unwrap(res);
  },
  postDepreciation: async (month: number, year: number) => {
    const res = await apiClient.post<BffResponse<boolean>>(`${BASE}/depreciation/post`, { month, year });
    return unwrap(res);
  },
};
